import "std/math.zc"

fn mean_angle(aa: f64*, n: const int) -> f64 {
    let sin_sum = 0.0;
    let cos_sum = 0.0;
    for i in 0..n {
        sin_sum += Math::sin(aa[i] * Math::PI() / 180.0);
        cos_sum += Math::cos(aa[i] * Math::PI() / 180.0);
    }
    return Math::atan2(sin_sum / n, cos_sum / n) * 180.0 / Math::PI();
}

