import "std/sort.zc"

fn median(a: f64*, len: const usize) -> f64 {
    // Avoid mutating 'a' by copying it to a new buffer 'b'.
    let bytes = len * sizeof(f64);
    autofree let b = (f64*)malloc(bytes);
    memcpy(b, a, bytes);
    sort_double(b, len);
    let hl = len / 2;
    let med = len % 2 ? b[hl] : (b[hl - 1] + b[hl]) / 2.0;
    return med;
}

