fn mode<T>(a: T*, n: const usize) {
    if n == 0 {
        println "There are no modes as the array is empty.";
        return;
    }
    let m = Map<int>::new();
    for i in 0..n {
        let k = "{a[i]}";
        if m.contains(k) {
            let val = m[k].unwrap();
            m.put(k, ++val);
        } else {
            m.put(k, 1);
        }
    }
    let most = 0;
    for entry in m {
        if entry.val > most { most = entry.val; }
    }
    let modes = Vec<string>::new();
    for entry in m {
        if entry.val == most { modes << entry.key; }
    }
    print "For the array : [";
    for i in 0..n { print "{a[i]}, "; }
    println "\b\b]";
    print "  mode(s)     : ";
    for mo in modes { print "{mo}, "; }
    println "\b\b \n  occurrences : {most}";
}

fn main() {
    let a = [1, 3, 5, 7, 1, 3, 1, 2, 3];
    mode<int>(a, 9);
    println "";
    let b = ["a", "b", "c", "a", "b", "a", "b", "b", "c"];
    mode<string>(b, 9);
}

import "std/math.zc"

fn a_mean(a: f64*, len: const usize) -> f64 {
    let sum = 0.0;
    for i in 0..len { sum += a[i]; }
    return sum / (f64)len;
}

fn g_mean(a: f64*, len: const usize) -> f64 {
    let prod = 1.0;
    for i in 0..len { prod *= a[i]; }
    return Math::pow(prod, 1.0 / (f64)len);
}

fn h_mean(a: f64*, len: const usize) -> f64 {
    let sum = 0.0;
    for i in 0..len { sum += 1.0 / a[i]; }
    return 1.0 / sum * (f64)len;
}

fn main() {
    let a: f64[10];
    for i in 0..10 { a[i] = (f64)(i + 1); }
    let am = a_mean(a, 10);
    let gm = g_mean(a, 10);
    let hm = h_mean(a, 10);
    let cmp = (am >= gm && gm >= hm) ? "true" : "false";
    println "For the numbers 1 to 10:";
    println "  Arithmetic mean = {am:g}";
    println "  Geometric mean  = {gm:0.14f}";
    println "  Harmonic mean   = {hm:0.14f}";
    println "  A >= G >= H     = {cmp}";
}

import "std/math.zc"

fn rms(a: f64[], len: const int) -> f64 {
    let sum = 0.0;
    for i in 0..len { sum += a[i] * a[i]; }
    return Math::sqrt(sum / len);
}

