fn str_occurs(s: string, t: string) -> int {
    let ptr = s;
    let count = 0;
    let l = strlen(t);
    if l == 0 { return -1; }
    loop {
        ptr = strstr(ptr, t);
        if ptr {
            count++;
            ptr += l;
        } else {
            break;
        }
    }
    return count;
}

