def BS2 = "\x08\x08";

fn list_divide(a: int*, c: const usize, n: const int) {
    assert(n > 0, "'n' must be a positive integer.");
    let q = c / n;
    let r = c % n;
    let p = Vec<int>::new();
    if r > 0 {
        for i in 1..=r { p << (q + 1); }
    }
    // Only include non-empty parts.
    if q > 0 {
        for i in 1..=(n - r) { p << q; }
    }
    let pc = p.length();
    let res = Vec<Vec<int>>::new();
    let start = 0;
    for i in 0..pc {
        let chunk = Vec<int>::new()
        let end = start + p[i];
        for j in start..end { chunk << a[j]; }
        res << chunk;
        start = end;
    }

    print "[";
    for chunk in res {
        print "[";
        for i in chunk { print "{i}, "; }
        print "{BS2}], ";
    }
    println "{BS2}]";
}

