fn padovan_n(n: int, t: usize, p: int*) {
    if n < 2 || t < 3 { 
        for i in 0..t { p[i] = 1; }
        return;
    }
    padovan_n(n - 1, t, p);
    for i in (n + 1)..t {
        p[i] = 0;
        for j in (i - 2)..=(i - n - 1) step -1 { p[i] += p[j]; }
    }
}

