fn rep_string(s: char*) {
    let rep: char[10];
    rep[0] = '\0';
    let size = strlen(s);
    if size >= 2 {
        for i in 0..size {
            assert(s[i] == '0' || s[i] == '1', "Argument is not a binary string.");
        }
        for len in 1..=size / 2 {
            let t: char[10];
            substring(s, t, 0, len);
            let n = size / len;
            let r = size % len;
            let u: char[20];
            mul_string(t, u, n);
            strncat(u, t, r);
            if !strcmp(u, s) {
                strcpy(rep, t);
                rep[strlen(t)] = '\0';
            }
        }
    }
    print "{s:10s} -> ";
    if strlen(rep) > 0 {
        println "{rep}";
    } else {
        println "Not a rep-string";
    }
}

