fn sedol_checkdigit(s: const string) -> int {
    if strlen(s) != 6 { return -1; }
    let weights: int[6] = [1, 3, 1, 7, 3, 9];
    let sum = 0;
    for i in 0..=5 {
        let c = s[i];
        if !isupper(c) && !isdigit(c) { return -1; }
        if is_upper_vowel(c) { return -1; }
        let j = (c <= '9') ? c - '0' : c - 'A' + 10;
        sum += j * weights[i];
    }
    return (10 - sum % 10) % 10;
}

