import "std/vec.zc"

fn sieve_of_pritchard(limit: usize) -> Vec<int> {
    let s = Vec<bool>::new();
    s.grow_to_fit(limit + 1);
    for i in 0..=limit {
        s << false;
    }
    s.set(1, true);

    let primes = Vec<int>::new();
    let pr: usize = 1;
    let p: usize = 2;

    while p * p <= limit {
        let pr_next = pr * p;

        if pr_next <= limit {
            for k in 1..p {
                for w in 1..=pr {
                    if s.get(w) {
                        s.set(w + k * pr, true);
                    }
                }
            }
            pr = pr_next;
        } else {
            for w in 1..=pr {
                if s.get(w) {
                    let mut_k = 1;
                    let current_pos = w + mut_k * pr;
                    while current_pos <= limit {
                        s.set(current_pos, true);
                        mut_k = mut_k + 1;
                        current_pos = w + mut_k * pr;
                    }
                }
            }
            pr = limit;
        }

        for w in (pr / p)..=1 step -1 {
            if s.get(w) {
                s.set(w * p, false);
            }
        }

        primes << (int)p;

        let next_p = p + 1;
        while next_p <= limit {
            let rem = next_p % pr;
            let wheel_pos = (rem == 0) ? pr : rem;
            if s.get(wheel_pos) {
                break;
            }
            next_p = next_p + 1;
        }
        p = next_p;
    }

    if pr < limit {
        for w in 1..=pr {
            if s.get(w) {
                let mut_k = 1;
                let current_pos = w + mut_k * pr;
                while current_pos <= limit {
                    s.set(current_pos, true);
                    mut_k = mut_k + 1;
                    current_pos = w + mut_k * pr;
                }
            }
        }
    }

    for i in 2..=limit {
        if s.get(i) {
            primes << (int)i;
        }
    }

    return primes;
}

fn main() {
    let limit: usize = 150;
    let primes = sieve_of_pritchard(limit);

    print "Primes up to {limit}: [";
    for i in 0..primes.len {
        print "{primes[i]}";
        if i < primes.len - 1 {
            print ", ";
        }
    }
    println "]";
    println "Total primes found: {primes.len}";
}

