// Other variable related facilities: Manifest Constants (compile-time only)
def GLOBAL_LIMIT = 1024;

fn main() {
    /* Declaration & Initialization (Type inferred automatically) */
    let a = 10;

    /* Assignment */
    a = 20;

    /* Datatypes (Explicit type annotations) */
    let my_int: int = 42;               // Standard 32-bit integer
    let my_float: f32 = 3.14;           // Floating point
    let my_bool: bool = true;           // Boolean
    let my_string: string = "Rosetta";  // Null-terminated C-string
    let my_u8: u8 = 255;                // Fixed-width unsigned 8-bit integer
    let my_c_long: c_long = 10000;      // C interop type (size varies by platform)

    // Read-only variables use the `const` type qualifier
    let max_retries: const int = 3;
    // max_retries = 5; // This would cause a compiler error

    /* Scope */
    {
        // Block scope: shadows the outer variable 'a'
        let a = 50;
        println "Inner scope 'a': {a}";

        // Other facilities: `autofree` automatically frees resources when scope exits
        // autofree let buffer = malloc(GLOBAL_LIMIT);
    }
    println "Outer scope 'a' remains: {a}";

    /* Referencing */
    // Zen C uses explicit pointers for referencing
    let ref_a: int* = &a; 
    *ref_a = 30; // Dereferencing to mutate the original variable
    println "Mutated 'a' via reference: {a}";

    /* Other facilities: Tuples and Destructuring */
    // Variables can be grouped and destructured in a single line
    let pair = (1, "Apple");
    let (id, name) = pair;

    println "Destructured Tuple - ID: {id}, Name: {name}";
}

import "std/core.zc"
import "std/math.zc"

struct Vector {
    x: double;
    y: double;
}

impl Vector {
    // Standard initialization
    fn new(x: double, y: double) -> Vector {
        return Vector { x: x, y: y };
    }

    // Initialize from start and end points
    fn from_points(x1: double, y1: double, x2: double, y2: double) -> Vector {
        return Vector { x: x2 - x1, y: y2 - y1 };
    }

    // Initialize from angle and length
    fn from_polar(angle: double, length: double) -> Vector {
        return Vector {
            x: length * Math::cos(angle),
            y: length * Math::sin(angle)
        };
    }

    // Maps to the '+' operator
    fn add(self, other: Vector) -> Vector {
        return Vector { x: self.x + other.x, y: self.y + other.y };
    }

    // Maps to the '-' operator
    fn sub(self, other: Vector) -> Vector {
        return Vector { x: self.x - other.x, y: self.y - other.y };
    }

    // Maps to the '*' operator
    fn mul(self, scalar: double) -> Vector {
        return Vector { x: self.x * scalar, y: self.y * scalar };
    }

    // Maps to the '/' operator
    fn div(self, scalar: double) -> Vector {
        if (scalar == 0.0) {
            println "Warning: Division by zero vector scalar!";
            return *self;
        }
        return Vector { x: self.x / scalar, y: self.y / scalar };
    }

    // Implicitly called during string interpolation
    fn to_string(self) -> char* {
        let buf = (char*)malloc(64);
        sprintf(buf, "Vector(x: %.2f, y: %.2f)", self.x, self.y);
        return buf;
    }

    fn show(self) {
        let s = self.to_string();
        println "{s}";
        free(s);
    }
}

fn main() {
    // Initialization
    let v1 = Vector::new(3.0, 4.0);
    println "v1 (new): {v1}";

    let v2 = Vector::from_points(0.0, 0.0, -1.0, 2.0);
    println "v2 (from_points): {v2}";

    println "v_polar (from_polar): {Vector::from_polar(Math::PI() / 4.0, 5.0)}";

    println "";

    // Operations
    println "v1 + v2: {v1 + v2}";
    println "v1 - v2: {v1 - v2}";
    println "v1 * 2.5: {v1 * 2.5}";
    println "v1 / 2.0: {v1 / 2.0}";
}

struct Vector3 {
    x: double;
    y: double;
    z: double;
}

impl Vector3 {
    fn new(x: double, y: double, z: double) -> Vector3 {
        return Vector3 { x: x, y: y, z: z };
    }

    fn dot(self, other: Vector3) -> double {
        return (self.x * other.x) + (self.y * other.y) + (self.z * other.z);
    }

    fn cross(self, other: Vector3) -> Vector3 {
        return Vector3 {
            x: (self.y * other.z) - (self.z * other.y),
            y: (self.z * other.x) - (self.x * other.z),
            z: (self.x * other.y) - (self.y * other.x)
        };
    }

    // Scalar triple product: a • (b x c)
    fn scalar_triple(self, b: Vector3, c: Vector3) -> double {
        return self.dot(b.cross(c));
    }

    // Vector triple product: a x (b x c)
    fn vector_triple(self, b: Vector3, c: Vector3) -> Vector3 {
        return self.cross(b.cross(c));
    }

    // Implicitly called during string interpolation
    fn to_string(self) -> char* {
        let buf = (char*)malloc(128);
        sprintf(buf, "(%.1f, %.1f, %.1f)", self.x, self.y, self.z);
        return buf;
    }
}

fn main() {
    let a = Vector3::new(3.0, 4.0, 5.0);
    let b = Vector3::new(4.0, 3.0, 5.0);
    let c = Vector3::new(-5.0, -12.0, -13.0);

    println "Vectors:";
    println "a = {a}";
    println "b = {b}";
    println "c = {c}";
    println "";

    println "a . b       = {a.dot(b)}";
    println "a x b       = {a.cross(b)}";
    println "a . (b x c) = {a.scalar_triple(b, c)}";
    println "a x (b x c) = {a.vector_triple(b, c)}";
}

import "std/fs.zc"

fn main() {
    let filename = "output.txt";
    let content = "Hello, Zen C!";

    // Open the file in "write" mode (overwrites if it exists, creates if not)
    let res = File::open(filename, "wb");
    if res.is_err() {
        eprintln "Error opening file for writing: {res.err}";
        return 1;
    }

    let f = res.unwrap();
    let write_res = f.write_string(content);

    // Explicit error handling for the write operation
    if write_res.is_err() {
        eprintln "Error writing to file: {write_res.err}";
        f.close();
        return 1;
    }

    f.close();
    println "Successfully wrote to {filename}";
}
